@app.route('/logout')
def logout():
    """Log out the user by clearing the session and optionally redirecting to provider logout."""
    # Get the id_token before clearing session (needed for some providers' logout)
    id_token_hint = None
    if 'tokens' in session:
        id_token_hint = session['tokens'].get('id_token')

    # Clear the session
    session.clear()

    # Check if the provider supports end_session_endpoint (RP-Initiated Logout)
    try:
        discovery_doc = get_oidc_discovery()
        end_session_endpoint = discovery_doc.get('end_session_endpoint')

        if end_session_endpoint:
            logout_params = {
                'post_logout_redirect_uri': url_for('index', _external=True),
            }
            if id_token_hint:
                logout_params['id_token_hint'] = id_token_hint

            logout_url = f"{end_session_endpoint}?{urlencode(logout_params)}"
            return redirect(logout_url)
    except Exception:
        pass

    return redirect(url_for('index'))


